document.addEventListener(`DOMContentLoaded`,()=>{document.querySelectorAll(`.video-player`).forEach(e=>{let t=e.querySelector(`.js-video-player`),n=e.querySelector(`.js-video-btn`);if(!t||!n)return;let r=()=>{t.paused?(t.play(),n.classList.add(`is-playing`)):(t.pause(),n.classList.remove(`is-playing`))};n.addEventListener(`click`,r),t.addEventListener(`click`,r),t.addEventListener(`ended`,()=>{n.classList.remove(`is-playing`)})})});